import { Dialog as DialogPrimitive, useDialog, useDialogContext } from '@ark-ui/react/dialog';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import { CloseButton } from '../close-button';
import styles from './Dialog.module.css';

const DEFAULT_CLOSE_BUTTON_LABEL = 'Close dialog';

type DialogRootProps = ComponentProps<typeof DialogPrimitive.Root> & OverlayPortalProps;
type DialogRootProviderProps = ComponentProps<typeof DialogPrimitive.RootProvider> &
  OverlayPortalProps;

function DialogRoot({ portalled, portalRef, ...props }: DialogRootProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <DialogPrimitive.Root {...props} />
    </OverlayPortalProvider>
  );
}

function DialogRootProvider({ portalled, portalRef, ...props }: DialogRootProviderProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <DialogPrimitive.RootProvider {...props} />
    </OverlayPortalProvider>
  );
}

const DialogTrigger = forwardRef<
  ComponentRef<typeof DialogPrimitive.Trigger>,
  ComponentProps<typeof DialogPrimitive.Trigger>
>(function DialogTrigger({ asChild, className, ...props }, ref) {
  return (
    <DialogPrimitive.Trigger
      ref={ref}
      asChild={asChild}
      data-slot="dialog-trigger"
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const DialogBackdrop = forwardRef<
  ComponentRef<typeof DialogPrimitive.Backdrop>,
  ComponentProps<typeof DialogPrimitive.Backdrop>
>(function DialogBackdrop({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <DialogPrimitive.Backdrop
        ref={ref}
        data-slot="dialog-backdrop"
        className={clsx(styles.backdrop, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const DialogPositioner = forwardRef<
  ComponentRef<typeof DialogPrimitive.Positioner>,
  ComponentProps<typeof DialogPrimitive.Positioner>
>(function DialogPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <DialogPrimitive.Positioner
        ref={ref}
        data-slot="dialog-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const DialogContent = forwardRef<
  ComponentRef<typeof DialogPrimitive.Content>,
  ComponentProps<typeof DialogPrimitive.Content>
>(function DialogContent({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Content
      ref={ref}
      data-slot="dialog-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const DialogTitle = forwardRef<
  ComponentRef<typeof DialogPrimitive.Title>,
  ComponentProps<typeof DialogPrimitive.Title>
>(function DialogTitle({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Title
      ref={ref}
      data-slot="dialog-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const DialogDescription = forwardRef<
  ComponentRef<typeof DialogPrimitive.Description>,
  ComponentProps<typeof DialogPrimitive.Description>
>(function DialogDescription({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Description
      ref={ref}
      data-slot="dialog-description"
      className={clsx(styles.description, normalizeClassName(className))}
      {...props}
    />
  );
});

const DialogCloseTrigger = forwardRef<
  ComponentRef<typeof DialogPrimitive.CloseTrigger>,
  ComponentProps<typeof DialogPrimitive.CloseTrigger>
>(function DialogCloseTrigger({ asChild, className, ...props }, ref) {
  return (
    <DialogPrimitive.CloseTrigger
      ref={ref}
      asChild={asChild}
      data-slot="dialog-close-trigger"
      className={clsx(!asChild && styles.closeTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const DialogCloseIcon = forwardRef<
  ComponentRef<typeof CloseButton.Root>,
  Omit<ComponentProps<typeof DialogPrimitive.CloseTrigger>, 'asChild'>
>(function DialogCloseIcon(
  { className, children, 'aria-label': ariaLabel = DEFAULT_CLOSE_BUTTON_LABEL, ...props },
  ref,
) {
  return (
    <DialogPrimitive.CloseTrigger asChild {...props}>
      <CloseButton.Root
        ref={ref}
        data-slot="dialog-close-icon"
        aria-label={ariaLabel}
        className={clsx(styles.closeIcon, normalizeClassName(className))}
      >
        {children}
      </CloseButton.Root>
    </DialogPrimitive.CloseTrigger>
  );
});

function DialogHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="dialog-header" className={clsx(styles.header, className)} {...props} />;
}

function DialogBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="dialog-body" className={clsx(styles.body, className)} {...props} />;
}

function DialogFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="dialog-footer" className={clsx(styles.footer, className)} {...props} />;
}

const Dialog = Object.assign(DialogRoot, {
  Root: DialogRoot,
  RootProvider: DialogRootProvider,
  Context: DialogPrimitive.Context,
  Trigger: DialogTrigger,
  Backdrop: DialogBackdrop,
  Positioner: DialogPositioner,
  Content: DialogContent,
  Title: DialogTitle,
  Description: DialogDescription,
  CloseTrigger: DialogCloseTrigger,
  CloseIcon: DialogCloseIcon,
  Header: DialogHeader,
  Body: DialogBody,
  Footer: DialogFooter,
});

export { Dialog, useDialog, useDialogContext };
export type { DialogRootProps, DialogRootProviderProps };

@layer moduix.components {
  .trigger,
  .closeTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--moduix-dialog-control-height, var(--moduix-size-md));
    margin: 0;
    padding: var(--moduix-dialog-control-padding-y, var(--moduix-spacing-1))
      var(--moduix-dialog-control-padding-x, var(--moduix-spacing-3-5));
    border: var(--moduix-dialog-control-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-dialog-control-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-dialog-control-radius, var(--moduix-radius-md));
    background-color: var(--moduix-dialog-control-bg, var(--moduix-color-background));
    color: var(--moduix-dialog-control-color, var(--moduix-color-foreground));
    font: inherit;
    font-size: var(--moduix-dialog-control-font-size, var(--moduix-text-md));
    line-height: var(--moduix-dialog-control-line-height, var(--moduix-line-height-text-md));
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--moduix-transition-default),
      border-color var(--moduix-transition-default),
      color var(--moduix-transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--moduix-dialog-control-bg-hover, var(--moduix-color-accent));
      }
    }

    &:focus-visible {
      outline: var(
          --moduix-dialog-focus-ring-width,
          var(--moduix-dialog-control-border-width, var(--moduix-border-width-sm))
        )
        solid var(--moduix-dialog-focus-ring-color, var(--moduix-color-ring));
      outline-offset: calc(
        var(
            --moduix-dialog-focus-ring-width,
            var(--moduix-dialog-control-border-width, var(--moduix-border-width-sm))
          ) *
          -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--moduix-opacity-disabled);
    }
  }

  .backdrop {
    position: fixed;
    z-index: calc(var(--moduix-z-backdrop) + var(--layer-index, 0));
    inset: 0;
    min-height: 100dvh;
    background-color: var(
      --moduix-dialog-backdrop-bg,
      var(--moduix-backdrop-bg, var(--moduix-color-overlay))
    );
    backdrop-filter: var(--moduix-backdrop-filter, blur(var(--moduix-dialog-backdrop-blur, 4px)));

    &[data-state='open'] {
      animation: dialog-backdrop-in
        var(--moduix-dialog-backdrop-transition, var(--moduix-transition-default));
    }

    &[data-state='closed'] {
      animation: dialog-backdrop-out
        var(--moduix-dialog-backdrop-transition, var(--moduix-transition-default));
    }
  }

  .positioner {
    box-sizing: border-box;
    position: fixed;
    z-index: calc(var(--moduix-z-modal) + var(--layer-index, 0));
    inset: 0;
    display: grid;
    place-items: center;
    overflow-y: auto;
    overscroll-behavior: contain;
    scrollbar-gutter: stable both-edges;
    padding: var(--moduix-dialog-positioner-padding, var(--moduix-spacing-4));
  }

  .content {
    box-sizing: border-box;
    position: relative;
    width: min(
      var(--moduix-dialog-width, 28rem),
      var(--moduix-dialog-max-width, calc(100vw - var(--moduix-spacing-8, 2rem)))
    );
    max-width: 100%;
    max-height: calc(100dvh - var(--moduix-spacing-8, 2rem));
    padding: var(--moduix-dialog-padding, var(--moduix-spacing-6));
    border: var(--moduix-dialog-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-dialog-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-dialog-radius, var(--moduix-radius-lg));
    outline: 0;
    background-color: var(--moduix-dialog-bg, var(--moduix-color-popover));
    color: var(--moduix-dialog-color, var(--moduix-color-popover-foreground));
    box-shadow: var(--moduix-dialog-shadow, var(--moduix-shadow-lg));
    transform-origin: center top;
    scale: 1;
    translate: 0 0;
    transition:
      scale
        var(
          --moduix-dialog-nested-transition,
          var(--moduix-dialog-transition, var(--moduix-transition-default))
        ),
      translate
        var(
          --moduix-dialog-nested-transition,
          var(--moduix-dialog-transition, var(--moduix-transition-default))
        );

    &::after {
      content: '';
      position: absolute;
      z-index: 1;
      inset: 0;
      border-radius: inherit;
      background-color: var(--moduix-dialog-nested-overlay-bg, rgb(0 0 0 / 0.05));
      opacity: 0;
      pointer-events: none;
      transition: opacity
        var(
          --moduix-dialog-nested-transition,
          var(--moduix-dialog-transition, var(--moduix-transition-default))
        );
    }

    &[data-has-nested] {
      scale: calc(1 - var(--moduix-dialog-nested-scale-step, 0.05) * var(--nested-layer-count, 0));
      translate: 0
        calc(
          var(--moduix-dialog-nested-translate-step, var(--moduix-spacing-10)) *
            var(--nested-layer-count, 0)
        );

      &::after {
        opacity: 1;
      }
    }

    &[data-state='open'] {
      animation: dialog-content-in
        var(
          --moduix-dialog-transition,
          var(--moduix-popup-motion-duration, var(--moduix-duration-normal))
            var(--moduix-popup-motion-easing, var(--moduix-ease-in-out))
        );
    }

    &[data-state='closed'] {
      animation: dialog-content-out
        var(
          --moduix-dialog-transition,
          var(--moduix-popup-motion-duration, var(--moduix-duration-normal))
            var(--moduix-popup-motion-easing, var(--moduix-ease-in-out))
        );
    }
  }

  .header {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    align-items: start;
    gap: var(--moduix-dialog-header-gap, var(--moduix-spacing-1));

    & > [data-slot='dialog-title'] {
      grid-column: 1;
    }

    & > [data-slot='dialog-close-trigger'] {
      grid-column: 2;
      justify-self: end;
    }

    & > [data-slot='dialog-description'] {
      grid-column: 1 / -1;
    }
  }

  .title {
    margin: 0;
    color: var(
      --moduix-dialog-title-color,
      var(--moduix-dialog-color, var(--moduix-color-popover-foreground))
    );
    font-size: var(--moduix-dialog-title-font-size, var(--moduix-text-lg));
    font-weight: var(--moduix-dialog-title-font-weight, var(--moduix-weight-semibold));
    line-height: var(--moduix-dialog-title-line-height, var(--moduix-line-height-text-lg));
  }

  .description,
  .body {
    color: var(
      --moduix-dialog-description-color,
      var(--moduix-dialog-muted-color, var(--moduix-color-muted-foreground))
    );
    font-size: var(--moduix-dialog-description-font-size, var(--moduix-text-md));
    line-height: var(--moduix-dialog-description-line-height, var(--moduix-line-height-text-md));
  }

  .description {
    margin: 0;
  }

  .body {
    margin: var(--moduix-dialog-content-margin, var(--moduix-spacing-4) 0 0);
  }

  .footer {
    display: flex;
    justify-content: flex-end;
    gap: var(--moduix-dialog-footer-gap, var(--moduix-spacing-2));
    margin-top: var(--moduix-dialog-footer-margin-top, var(--moduix-spacing-6));
  }

  .closeIcon {
    --moduix-close-button-size: var(--moduix-dialog-close-icon-size, var(--moduix-spacing-7));
    --moduix-close-button-radius: var(--moduix-dialog-close-icon-radius, var(--moduix-radius-md));
    --moduix-close-button-color: var(
      --moduix-dialog-close-icon-color,
      var(--moduix-dialog-muted-color, var(--moduix-color-muted-foreground))
    );
    --moduix-close-button-color-hover: var(
      --moduix-dialog-close-icon-color-hover,
      var(
        --moduix-dialog-close-icon-color,
        var(--moduix-dialog-color, var(--moduix-color-popover-foreground))
      )
    );
    --moduix-close-button-bg: var(--moduix-dialog-close-icon-bg, transparent);
    --moduix-close-button-bg-hover: var(
      --moduix-dialog-close-icon-bg-hover,
      var(--moduix-color-accent)
    );
    --moduix-close-button-focus-ring-color: var(
      --moduix-dialog-close-icon-focus-ring-color,
      var(--moduix-dialog-focus-ring-color, var(--moduix-color-ring))
    );
    --moduix-close-button-icon-size: var(
      --moduix-dialog-close-icon-glyph-size,
      var(--moduix-spacing-3)
    );
    position: absolute;
    z-index: 2;
    inset-block-start: var(--moduix-dialog-close-icon-inset-block-start, var(--moduix-spacing-4));
    inset-inline-end: var(--moduix-dialog-close-icon-inset-inline-end, var(--moduix-spacing-4));
  }

  @keyframes dialog-backdrop-in {
    from {
      opacity: var(--moduix-dialog-backdrop-starting-opacity, 0);
      backdrop-filter: var(--moduix-dialog-backdrop-starting-blur, none);
    }
  }

  @keyframes dialog-backdrop-out {
    to {
      opacity: var(--moduix-dialog-backdrop-ending-opacity, 0);
      backdrop-filter: var(--moduix-dialog-backdrop-ending-blur, none);
    }
  }

  @keyframes dialog-content-in {
    from {
      opacity: var(
        --moduix-dialog-content-starting-opacity,
        var(--moduix-popup-motion-starting-opacity, 0)
      );
      translate: var(
          --moduix-dialog-content-starting-translate-x,
          var(--moduix-popup-motion-starting-translate-x, 0)
        )
        var(
          --moduix-dialog-content-starting-translate-y,
          var(--moduix-popup-motion-starting-translate-y, 0)
        );
      scale: var(
        --moduix-dialog-content-starting-scale,
        var(--moduix-popup-motion-starting-scale, var(--moduix-scale-popup))
      );
    }
  }

  @keyframes dialog-content-out {
    to {
      opacity: var(
        --moduix-dialog-content-ending-opacity,
        var(--moduix-popup-motion-ending-opacity, 0)
      );
      translate: var(
          --moduix-dialog-content-ending-translate-x,
          var(--moduix-popup-motion-ending-translate-x, 0)
        )
        var(
          --moduix-dialog-content-ending-translate-y,
          var(--moduix-popup-motion-ending-translate-y, 0)
        );
      scale: var(
        --moduix-dialog-content-ending-scale,
        var(--moduix-popup-motion-ending-scale, var(--moduix-scale-popup))
      );
    }
  }
}
